mapper.select:
SELECT id, kb_id, query_text, response_text, hit_count, created_at, expires_at,
       1 - (query_embedding <=> #{queryEmbedding}::vector) AS similarity
FROM semantic_cache
WHERE kb_id = #{kbId}
  AND (expires_at IS NULL OR expires_at > NOW())
  AND 1 - (query_embedding <=> #{queryEmbedding}::vector) > #{threshold}
ORDER BY query_embedding <=> #{queryEmbedding}::vector
LIMIT #{limit}
